import type { Env } from "./types";

const CACHE_TTL_SECONDS = 86400; // 24 hours

export async function hashLicenseKey(key: string): Promise<string> {
  const encoder = new TextEncoder();
  const data = encoder.encode(key);
  const hashBuffer = await crypto.subtle.digest("SHA-256", data);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map((b) => b.toString(16).padStart(2, "0")).join("");
}

export async function validateLicense(
  licenseKey: string,
  env: Env
): Promise<{ valid: boolean; reason?: string }> {
  const hash = await hashLicenseKey(licenseKey);
  const cacheKey = `license:${hash}`;

  // Check cache first
  const cached = await env.KV.get(cacheKey);
  if (cached === "valid") {
    return { valid: true };
  }
  if (cached === "invalid") {
    return { valid: false, reason: "License is not active." };
  }

  // Validate against LemonSqueezy
  try {
    const response = await fetch(
      "https://api.lemonsqueezy.com/v1/licenses/validate",
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          license_key: licenseKey,
          instance_name: "promptcraft-cloud",
        }),
      }
    );

    if (!response.ok) {
      // LemonSqueezy API error — don't cache, allow retry
      return { valid: false, reason: "License validation service unavailable." };
    }

    const data = (await response.json()) as {
      valid: boolean;
      license_key?: {
        status?: string;
      };
    };

    if (data.valid && data.license_key?.status === "active") {
      await env.KV.put(cacheKey, "valid", { expirationTtl: CACHE_TTL_SECONDS });
      return { valid: true };
    }

    // Cache invalid result for a shorter period (1 hour) to allow re-validation
    await env.KV.put(cacheKey, "invalid", { expirationTtl: 3600 });
    return {
      valid: false,
      reason: `License status: ${data.license_key?.status ?? "unknown"}.`,
    };
  } catch {
    // Network error — don't cache, don't block user
    return { valid: false, reason: "Unable to validate license. Try again." };
  }
}
